void solve(int CASE)
{
	ll n, m, h; cin >> n >> m >> h;
	var Q = vector<pll>(m + 1);
	fa(i, 1, m) {
		ll p, f; cin >> p >> f;
		Q[i] = { p,f };
	}

	var check = [&](ll mid)->bool {
		var d = vector<ll>(n + 10);
		fa(i, 1, mid) {
			const var& [p, f] = Q[i];
			ll L = max(1ll, p - f);
			ll R = min(n, p + f);

			ll l = L, r = p;
			ll la1 = f - (r - l);
			ll lan = f;
			ll ld = 1;
			d[l] += la1;
			d[l + 1] += ld - la1;
			d[r + 1] += -ld - lan;
			d[r + 2] += lan;

			l = p + 1, r = R;
			ll ra1 = f - 1;
			ll ran = f - 1 - (r - l);
			ll rd = -1;
			d[l] += ra1;
			d[l + 1] += rd - ra1;
			d[r + 1] += -rd - ran;
			d[r + 2] += ran;
		}

		fa(i, 1, n)d[i] += d[i - 1];
		fa(i, 1, n) {
			d[i] += d[i - 1];
			if (d[i] > h)return 1;
		}
		return 0;
		};

	ll l = 1, r = m, ans = 0;
	while (l <= r) {
		ll mid = l + r >> 1;
		if (check(mid)) {
			r = mid - 1;
			ans = mid;
		}
		else l = mid + 1;
	}

	if (ans)cout << "Yes" << endl << ans << endl;
	else cout << "No" << endl;
	return;
}
